import React, { useState, useEffect } from 'react';
import { PlayIcon, CloudIcon, ExclamationTriangleIcon, TruckIcon } from '@heroicons/react/24/outline';
import { simulationAPI, adminAPI } from '../../services/api';
import toast from 'react-hot-toast';

const AdminSimulation = () => {
  const [scenarios, setScenarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [simulationRunning, setSimulationRunning] = useState(false);
  const [workers, setWorkers] = useState([]);
  const [selectedWorker, setSelectedWorker] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [scenariosRes, workersRes] = await Promise.all([
        simulationAPI.getScenarios(),
        adminAPI.getAllWorkers({ limit: 100 })
      ]);
      setScenarios(scenariosRes.data.data);
      const workersList = workersRes.data.data || [];
      setWorkers(workersList);
      if (workersList.length > 0) {
        setSelectedWorker(workersList[0]._id);
      }
    } catch (error) {
      toast.error('Failed to fetch simulation data');
    } finally {
      setLoading(false);
    }
  };

  const runSimulation = async (scenarioId) => {
    try {
      if (!selectedWorker) {
        toast.error('No workers available for simulation');
        return;
      }

      setSimulationRunning(true);

      const simulationData = {
        scenarioId,
        workerId: selectedWorker
      };

      await simulationAPI.runSimulation(simulationData);
      toast.success('Simulation completed successfully');

    } catch (error) {
      toast.error('Failed to run simulation');
    } finally {
      setSimulationRunning(false);
    }
  };

  const getScenarioIcon = (id) => {
    switch (id) {
      case 'heavy_rain':
        return <CloudIcon className="h-8 w-8 text-blue-600" />;
      case 'extreme_pollution':
        return <ExclamationTriangleIcon className="h-8 w-8 text-yellow-600" />;
      case 'severe_traffic':
        return <TruckIcon className="h-8 w-8 text-red-600" />;
      default:
        return <PlayIcon className="h-8 w-8 text-gray-600" />;
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Simulation Center</h1>
        <p className="text-gray-600">Test the system with simulated events</p>
      </div>

      {/* Worker Selection */}
      <div className="card">
        <div className="card-header">
          <h3 className="card-title">Select Worker for Simulation</h3>
        </div>
        <div className="card-content">
          {workers.length === 0 ? (
            <p className="text-gray-600">No workers available. Please create a worker first.</p>
          ) : (
            <select
              value={selectedWorker || ''}
              onChange={(e) => setSelectedWorker(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent"
            >
              <option value="">-- Select a worker --</option>
              {workers.map((worker) => (
                <option key={worker._id} value={worker._id}>
                  {worker.personalInfo?.firstName} {worker.personalInfo?.lastName} ({worker.personalInfo?.email})
                </option>
              ))}
            </select>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {scenarios.map((scenario) => (
          <div key={scenario.id} className="card">
            <div className="card-header">
              <div className="flex items-center">
                {getScenarioIcon(scenario.id)}
                <div className="ml-4">
                  <h3 className="text-lg font-medium text-gray-900">{scenario.name}</h3>
                  <p className="text-sm text-gray-600">{scenario.description}</p>
                </div>
              </div>
            </div>
            <div className="card-content">
              <div className="space-y-2">
                <div className="text-sm">
                  <span className="font-medium">Triggers:</span>
                  <ul className="mt-1 space-y-1 text-gray-600">
                    {scenario.weather && (
                      <li>• Rainfall: {scenario.weather.rainfall}mm/hr</li>
                    )}
                    {scenario.pollution && (
                      <li>• AQI: {scenario.pollution.aqi}</li>
                    )}
                    {scenario.traffic && (
                      <li>• Congestion: {scenario.traffic.congestionLevel}/10</li>
                    )}
                  </ul>
                </div>
                <div className="text-sm">
                  <span className="font-medium">Thresholds:</span>
                  <ul className="mt-1 space-y-1 text-gray-600">
                    {scenario.thresholds && Object.entries(scenario.thresholds).map(([key, value]) => (
                      <li key={key}>• {key}: {value}</li>
                    ))}
                  </ul>
                </div>
              </div>
            </div>
            <div className="card-footer">
              <button
                onClick={() => runSimulation(scenario.id)}
                disabled={simulationRunning}
                className="btn-primary w-full"
              >
                {simulationRunning ? 'Running...' : 'Run Simulation'}
              </button>
            </div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="card-header">
          <h3 className="card-title">Simulation Controls</h3>
        </div>
        <div className="card-content">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <button
              onClick={() => simulationAPI.clearSimulationData()}
              className="btn-outline"
            >
              Clear Simulation Data
            </button>
            <button
              onClick={() => window.location.reload()}
              className="btn-secondary"
            >
              Refresh Status
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminSimulation;
